def _encode_header_payload(payload, max_bytes):
    try:
        raw = json.dumps(payload, separators=(",", ":"), ensure_ascii=False).encode("utf-8")
        b64 = base64.b64encode(raw).decode("ascii")
        if len(b64.encode("utf-8")) <= max_bytes:
            return b64
        minimal = {
            "v": payload.get("v", 1),
            "elapsed_ms": payload.get("elapsed_ms"),
            "count": payload.get("count"),
            "results": [
                {
                    "url": r.get("url"),
                    "ok": r.get("ok"),
                    "status": r.get("status"),
                    "error": r.get("error"),
                }
                for r in (payload.get("results") or [])
            ],
        }
        raw2 = json.dumps(minimal, separators=(",", ":"), ensure_ascii=False).encode("utf-8")
        b642 = base64.b64encode(raw2).decode("ascii")
        if len(b642.encode("utf-8")) <= max_bytes:
            return b642
        return _truncate(b642, max_bytes)
    except Exception:
        return None


def _set_header(headers, name, value):
    headers[name.lower()] = [{"key": name, "value": value}]


def _truncate(s, max_bytes):
    b = s.encode("utf-8")
    if len(b) <= max_bytes:
        return s
    b = b[:max_bytes]
    return b.decode("utf-8", errors="ignore")


def _bytes_to_text(b, content_type):
    charset = "utf-8"
    if content_type:
        ct = content_type.lower()
        if "charset=" in ct:
            try:
                charset = ct.split("charset=", 1)[1].split(";", 1)[0].strip() or "utf-8"
            except Exception:
                charset = "utf-8"
    try:
        return b.decode(charset, errors="replace")
    except Exception:
        return b.decode("utf-8", errors="replace")


def _try_parse_json(text):
    if not text:
        return None
    t = text.strip()
    if not t:
        return None
    if (t.startswith("{") and t.endswith("}")) or (t.startswith("[") and t.endswith("]")):
        try:
            return json.loads(t)
        except Exception:
            return None
    return None


def _is_private_host(host):
    h = (host or "").strip().lower()
    if not h:
        return True

    if h in ("localhost",):
        return True

    try:
        import ipaddress

        ip = ipaddress.ip_address(h)
        return ip.is_private or ip.is_loopback or ip.is_link_local or ip.is_multicast or ip.is_reserved
    except Exception:
        pass

    # Basic SSRF mitigation for obvious local domains
    if h.endswith(".local") or h.endswith(".internal") or h.endswith(".localhost"):
        return True

    return False